import argparse
import base64
import json
import re
import sys
import time
import uuid
from dataclasses import dataclass
from datetime import datetime, timezone
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from pathlib import Path
from typing import Any, Dict, Optional
from urllib.error import HTTPError, URLError
from urllib.parse import urljoin, urlsplit, urlunsplit
from urllib.request import Request, urlopen


HOP_BY_HOP_HEADERS = {
    "connection",
    "keep-alive",
    "proxy-authenticate",
    "proxy-authorization",
    "te",
    "trailer",
    "transfer-encoding",
    "upgrade",
}


@dataclass(frozen=True)
class ProxyConfig:
    upstream_base_url: str
    log_dir: Path
    timeout_seconds: float = 600.0


def create_handler(config: ProxyConfig):
    class LoggingProxyHandler(BaseHTTPRequestHandler):
        protocol_version = "HTTP/1.1"

        def do_GET(self):
            self._proxy()

        def do_POST(self):
            self._proxy()

        def do_OPTIONS(self):
            self._proxy()

        def log_message(self, format, *args):
            sys.stderr.write(
                "%s - - [%s] %s\n"
                % (self.client_address[0], self.log_date_time_string(), format % args)
            )

        def _proxy(self):
            started = time.time()
            body = self._read_body()
            upstream_url = _build_upstream_url(config.upstream_base_url, self.path)
            headers = _forward_headers(dict(self.headers))
            request_record = {
                "method": self.command,
                "path": self.path,
                "url": upstream_url,
                "headers": _redact_headers(dict(self.headers)),
                **_decode_body(body, self.headers.get("Content-Type")),
            }
            status: int
            response_headers: Dict[str, str]
            response_body: bytes
            error: Optional[str] = None

            try:
                upstream_request = Request(
                    upstream_url,
                    data=body if self.command not in {"GET", "HEAD"} else None,
                    headers=headers,
                    method=self.command,
                )
                with urlopen(upstream_request, timeout=config.timeout_seconds) as response:
                    status = response.status
                    response_headers = dict(response.headers)
                    response_body = response.read()
            except HTTPError as exc:
                status = exc.code
                response_headers = dict(exc.headers)
                response_body = exc.read()
            except URLError as exc:
                status = 502
                response_headers = {"Content-Type": "application/json"}
                error = str(exc.reason)
                response_body = json.dumps(
                    {
                        "error": {
                            "message": f"Upstream request failed: {error}",
                            "type": "upstream_error",
                        }
                    },
                    ensure_ascii=False,
                ).encode("utf-8")

            elapsed_ms = int((time.time() - started) * 1000)
            log_entry = {
                "id": uuid.uuid4().hex,
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "duration_ms": elapsed_ms,
                "client": {
                    "address": self.client_address[0],
                    "port": self.client_address[1],
                },
                "request": request_record,
                "upstream": {
                    "base_url": config.upstream_base_url,
                    "url": upstream_url,
                    "status": status,
                    "error": error,
                },
                "response": {
                    "headers": _redact_headers(response_headers),
                    **_decode_body(response_body, response_headers.get("Content-Type")),
                },
            }
            _write_log(config.log_dir, self.headers.get("x-upstream-session-id"), log_entry)
            self._send_response(status, response_headers, response_body)

        def _read_body(self) -> bytes:
            length = int(self.headers.get("Content-Length", "0") or "0")
            if length <= 0:
                return b""
            return self.rfile.read(length)

        def _send_response(
            self, status: int, response_headers: Dict[str, str], response_body: bytes
        ) -> None:
            self.send_response(status)
            for name, value in response_headers.items():
                if name.lower() in HOP_BY_HOP_HEADERS or name.lower() == "content-length":
                    continue
                self.send_header(name, value)
            self.send_header("Content-Length", str(len(response_body)))
            self.end_headers()
            self.wfile.write(response_body)

    return LoggingProxyHandler


def _build_upstream_url(upstream_base_url: str, request_path: str) -> str:
    base = upstream_base_url.rstrip("/") + "/"
    split_path = urlsplit(request_path)
    joined = urljoin(base, split_path.path.lstrip("/"))
    joined_split = urlsplit(joined)
    return urlunsplit(
        (
            joined_split.scheme,
            joined_split.netloc,
            joined_split.path,
            split_path.query,
            "",
        )
    )


def _forward_headers(headers: Dict[str, str]) -> Dict[str, str]:
    forwarded = {}
    for name, value in headers.items():
        lower = name.lower()
        if lower in HOP_BY_HOP_HEADERS or lower in {"host", "content-length"}:
            continue
        forwarded[name] = value
    return forwarded


def _redact_headers(headers: Dict[str, str]) -> Dict[str, str]:
    redacted = {}
    for name, value in headers.items():
        if name.lower() in {"authorization", "proxy-authorization", "x-api-key"}:
            redacted[name] = _redact_secret(value)
        else:
            redacted[name] = value
    return redacted


def _redact_secret(value: str) -> str:
    if len(value) <= 12:
        return "***"
    return value[:8] + "...redacted..." + value[-4:]


def _decode_body(body: bytes, content_type: Optional[str]) -> Dict[str, Any]:
    if not body:
        return {"raw": ""}
    is_json = content_type and "json" in content_type.lower()
    try:
        text = body.decode("utf-8")
    except UnicodeDecodeError:
        return {"base64": base64.b64encode(body).decode("ascii")}
    if is_json:
        try:
            return {"json": json.loads(text)}
        except json.JSONDecodeError:
            return {"raw": text}
    return {"raw": text}


def _write_log(log_dir: Path, session_id: Optional[str], log_entry: Dict[str, Any]) -> Path:
    safe_session_id = _safe_name(session_id or "default")
    session_dir = log_dir / safe_session_id
    session_dir.mkdir(parents=True, exist_ok=True)
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%S.%fZ")
    path = session_dir / f"{timestamp}-{log_entry['id']}.json"
    path.write_text(json.dumps(log_entry, ensure_ascii=False, indent=2), encoding="utf-8")
    return path


def _safe_name(value: str) -> str:
    safe = re.sub(r"[^A-Za-z0-9_.-]+", "_", value.strip())
    return safe[:120] or "default"


def serve(config: ProxyConfig, host: str, port: int) -> None:
    config.log_dir.mkdir(parents=True, exist_ok=True)
    server = ThreadingHTTPServer((host, port), create_handler(config))
    print(
        f"sglang_proxy listening on http://{host}:{port}; "
        f"upstream={config.upstream_base_url}; log_dir={config.log_dir}",
        flush=True,
    )
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("stopping sglang_proxy", flush=True)
    finally:
        server.server_close()


def parse_args(argv=None):
    parser = argparse.ArgumentParser(
        description="OpenAI-compatible logging proxy between MiroThinker and SGLang."
    )
    parser.add_argument("--host", default="127.0.0.1")
    parser.add_argument("--port", type=int, default=61003)
    parser.add_argument("--upstream", default="http://127.0.0.1:61002")
    parser.add_argument("--log-dir", type=Path, default=Path("logs/sglang_proxy"))
    parser.add_argument("--timeout-seconds", type=float, default=600.0)
    return parser.parse_args(argv)


def main(argv=None) -> None:
    args = parse_args(argv)
    serve(
        ProxyConfig(
            upstream_base_url=args.upstream,
            log_dir=args.log_dir,
            timeout_seconds=args.timeout_seconds,
        ),
        host=args.host,
        port=args.port,
    )


if __name__ == "__main__":
    main()

